'use strict';
/**
 * Shared helpers for AI Aquarium QA tests.
 * All tests run against the deployed BASE_URL via window._gameEngine.
 */

/**
 * Wait for Phaser to finish booting and the SimulationEngine to be attached.
 * @param {import('@playwright/test').Page} page
 * @param {number} [timeout=20000]
 */
async function waitForEngine(page, timeout = 20_000) {
  await page.waitForFunction(
    () => window._gameEngine &&
          window._gameEngine.characters &&
          window._gameEngine.characters.length === 3,
    { timeout }
  );
}

/**
 * Read the live engine state.
 * @param {import('@playwright/test').Page} page
 */
async function getEngineState(page) {
  return page.evaluate(() => {
    const eng = window._gameEngine;
    return {
      simTime: eng.getSimTimeString(),
      aiEnabled: eng.aiEngine?.enabled ?? false,
      characters: eng.characters.map(c => ({
        name: c.name,
        label: c.label,
        tx: c.tx,
        ty: c.ty,
        action: c.action,
        mood: c.mood,
        energy: c.energy,
      })),
      objectStates: eng.objectEngine.getAll().map(o => ({
        id: o.id,
        label: o.label,
        state: o.state,
      })),
    };
  });
}

/**
 * Poll engine state until predicate returns truthy, or timeout.
 * @param {import('@playwright/test').Page} page
 * @param {(state: object) => boolean} predicate
 * @param {number} [timeoutMs=30000]
 * @param {number} [intervalMs=500]
 */
async function pollEngineState(page, predicate, timeoutMs = 30_000, intervalMs = 500) {
  const deadline = Date.now() + timeoutMs;
  while (Date.now() < deadline) {
    const state = await getEngineState(page);
    if (predicate(state)) return state;
    await page.waitForTimeout(intervalMs);
  }
  throw new Error(`pollEngineState timed out after ${timeoutMs}ms`);
}

/**
 * Wait for /debug.html dashboard to finish loading.
 * Shared by m1-debug-dashboard, slot-system, talk-handshaking, fallback-logic specs.
 * @param {import('@playwright/test').Page} page
 * @param {number} [timeout=20000]
 */
async function waitForDashboard(page, timeout = 20_000) {
  await page.waitForSelector('#characters-grid', { timeout });
  await page.waitForSelector('#event-log', { timeout });
  await page.waitForFunction(
    () => {
      const cards = document.querySelectorAll('[id^="char-"]');
      if (cards.length < 3) return false;
      return cards[0].textContent.includes('Action');
    },
    { timeout }
  );
}

module.exports = { waitForEngine, getEngineState, pollEngineState, waitForDashboard };

