'use strict';
/**
 * REGRESSION — FRG-244
 * Characters face toward objects when interacting (and toward each other when talking).
 *
 * Tests run against the local dev server (http://localhost:5173) because this
 * feature lives in the feature/frg-244 branch, not yet deployed to Vercel.
 *
 * The page is served as a static file and does NOT expose window._gameEngine
 * by default, so we intercept index.html via page.route() and inject the
 * exposure before the script executes.
 *
 * Test layout:
 *   1. Object-facing regression — character faces the object it interacts with
 *   2. Talk facing (direct) — facing logic is correct for character-to-character
 *   3. Talk arrival facing — when a character walks to another and arrives, both face each other
 */
const { test, expect } = require('@playwright/test');

const LOCAL_URL = 'http://localhost:5173';

// ── helpers ──────────────────────────────────────────────────────────────────

/**
 * Intercept index.html served at / and inject window._gameEngine = engine
 * so tests can call page.evaluate(() => window._gameEngine.*).
 */
async function injectEngineExposure(page) {
  await page.route('**/', async (route) => {
    const response = await route.fetch();
    let body = await response.text();
    // Inject just before "// ── Initial state ──" at the bottom of the module script
    body = body.replace(
      '// ── Initial state ──',
      '// ── Initial state (QA injection) ──\nwindow._gameEngine = engine;'
    );
    await route.fulfill({ response, body });
  });
}

/**
 * Start the engine — click the overlay (click-to-start) then boost speed.
 */
async function startEngine(page, timeScale = 20) {
  // Click the overlay to start the sim
  const overlay = page.locator('#start-overlay');
  if (await overlay.isVisible()) {
    await overlay.click();
  }

  // Boost speed for faster interactions
  await page.evaluate((scale) => {
    if (window._gameEngine) window._gameEngine.timeScale = scale;
  }, timeScale);
}

/**
 * Poll engine snapshot until predicate returns truthy.
 */
async function pollSnapshot(page, predicate, timeoutMs = 45_000, intervalMs = 300) {
  const deadline = Date.now() + timeoutMs;
  while (Date.now() < deadline) {
    const snap = await page.evaluate(() => window._gameEngine.snapshot());
    if (predicate(snap)) return snap;
    await page.waitForTimeout(intervalMs);
  }
  throw new Error(`pollSnapshot timed out after ${timeoutMs}ms`);
}

/**
 * Given a character (tx, ty) and an object position ({tx, ty, tw?, th?}),
 * return the expected facing direction the character should have.
 */
function expectedFacingTowardObject(charTx, charTy, objPos) {
  const objCx = objPos.tx + (objPos.tw || 1) / 2;
  const objCy = objPos.ty + (objPos.th || 1) / 2;
  const dx = objCx - charTx;
  const dy = objCy - charTy;
  if (Math.abs(dx) >= Math.abs(dy)) {
    return dx > 0 ? 'right' : 'left';
  } else {
    return dy > 0 ? 'down' : 'up';
  }
}

/**
 * Given two tile positions, return the expected facing direction from pos1 → pos2.
 */
function expectedFacingTowardChar(fromTx, fromTy, toTx, toTy) {
  const dx = toTx - fromTx;
  const dy = toTy - fromTy;
  if (Math.abs(dx) >= Math.abs(dy)) {
    return dx > 0 ? 'right' : 'left';
  } else {
    return dy > 0 ? 'down' : 'up';
  }
}

// ── Tests ─────────────────────────────────────────────────────────────────────

test.describe('FRG-244: Character Facing', () => {
  // ── TEST 1: Object facing regression ──────────────────────────────────────

  test('character faces toward the object it interacts with', async ({ page }) => {
    test.setTimeout(90_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);

    // Wait for engine to be exposed
    await page.waitForFunction(() => window._gameEngine?.characters?.length === 3, { timeout: 15_000 });
    await startEngine(page, 20);

    // Poll until any character is in 'interacting' state with a targetObjectId
    const snap = await pollSnapshot(
      page,
      s => s.characters.some(c => c.action === 'interacting' && c.targetObjectId),
      60_000
    );

    const interacting = snap.characters.filter(c => c.action === 'interacting' && c.targetObjectId);
    expect(interacting.length, 'At least one character should be interacting with an object').toBeGreaterThanOrEqual(1);

    for (const char of interacting) {
      // Get the object's position from the engine
      const objPos = await page.evaluate((objId) => {
        const obj = window._gameEngine.objectEngine.get(objId);
        return obj ? { tx: obj.position.tx, ty: obj.position.ty, tw: obj.position.tw, th: obj.position.th } : null;
      }, char.targetObjectId);

      expect(objPos, `Object ${char.targetObjectId} should exist`).not.toBeNull();

      const expected = expectedFacingTowardObject(char.tx, char.ty, objPos);

      console.log(
        `${char.name} at (${char.tx},${char.ty}) → ${char.targetObjectId} at ` +
        `(${objPos.tx},${objPos.ty}): facing=${char.facing}, expected=${expected}`
      );

      expect(char.facing,
        `${char.name} should face ${expected} toward ${char.targetObjectId} but is facing ${char.facing}`
      ).toBe(expected);
    }
  });

  // ── TEST 2: Talk facing — direct engine manipulation ──────────────────────

  test('_updateFacing correctly orients a character toward another character', async ({ page }) => {
    test.setTimeout(30_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window._gameEngine?.characters?.length === 3, { timeout: 15_000 });

    // _updateFacing(dx, dy): dx is checked first (horizontal priority), then dy only if dx===0.
    // This is by design — the engine resolves the dominant axis BEFORE calling _updateFacing
    // for object interactions, but character-to-character facing passes raw deltas directly,
    // so horizontal direction takes priority when both dx and dy are non-zero.
    const facingResults = await page.evaluate(() => {
      const chars = window._gameEngine.characters;
      const maple = chars.find(c => c.id === 'maple');

      const results = [];

      const testCases = [
        // Pure cardinal directions (dx or dy === 0)
        { name: 'right (pure horizontal)',    dx:  3, dy:  0, expected: 'right' },
        { name: 'left (pure horizontal)',     dx: -3, dy:  0, expected: 'left'  },
        { name: 'down (pure vertical)',       dx:  0, dy:  3, expected: 'down'  },
        { name: 'up (pure vertical)',         dx:  0, dy: -3, expected: 'up'    },
        // Both non-zero: horizontal (dx) takes priority in _updateFacing
        { name: 'right wins over down',       dx:  1, dy:  3, expected: 'right' },
        { name: 'left wins over up',          dx: -1, dy: -3, expected: 'left'  },
      ];

      for (const tc of testCases) {
        maple._updateFacing(tc.dx, tc.dy);
        results.push({ case: tc.name, expected: tc.expected, actual: maple.facing });
      }

      return results;
    });

    for (const result of facingResults) {
      console.log(`Facing case "${result.case}": expected=${result.expected}, actual=${result.actual}`);
      expect(result.actual, `Facing case "${result.case}" failed`).toBe(result.expected);
    }
  });

  // ── TEST 3: Talk arrival — characters face each other when one arrives ─────

  test('characters face each other when one arrives near the other for conversation', async ({ page }) => {
    test.setTimeout(30_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window._gameEngine?.characters?.length === 3, { timeout: 15_000 });

    // Simulate the arrival handshake: set maple walking with a path to her destination,
    // set targetCharId = sol, then advance the engine enough to trigger arrival.
    // _updateCharacters checks: wasWalking && char.action === 'idle' (after update)
    // → if targetCharId set: face each other and clear targetCharId.
    const result = await page.evaluate(() => {
      const engine = window._gameEngine;
      const chars = engine.characters;
      const maple = chars.find(c => c.id === 'maple');
      const sol   = chars.find(c => c.id === 'sol');

      // Position sol to the right of maple's destination
      sol.tx   = 8;  sol.ty   = 5;

      // Set maple walking with a single-tile path (moveSpeed=2 tiles/s → 500ms/tile)
      maple.tx       = 4;  maple.ty = 5;
      maple.prevTx   = 4;  maple.prevTy = 5;
      maple.action   = 'walking';
      maple.path     = [{ tx: 5, ty: 5 }];  // destination tile
      maple.moveProgress = 0;
      maple.targetCharId = sol.id;

      // Reset facings to neutral so we can see the change
      maple.facing = 'down';
      sol.facing   = 'left';

      // Advance 1000ms (2 tile periods) → maple's path clears → action becomes 'idle'
      // then arrival handler fires: face each other, clear targetCharId
      engine._updateCharacters(1000);

      return {
        maple: { facing: maple.facing, tx: maple.tx, ty: maple.ty },
        sol:   { facing: sol.facing,   tx: sol.tx,   ty: sol.ty   },
        targetCharIdCleared: maple.targetCharId === null,
      };
    });

    console.log('After arrival, maple facing:', result.maple.facing, '| sol facing:', result.sol.facing);
    console.log('targetCharId cleared:', result.targetCharIdCleared);

    // Maple is at x=5, sol at x=8 → maple should face right, sol should face left
    expect(result.maple.facing, 'Maple should face right (toward Sol)').toBe('right');
    expect(result.sol.facing,   'Sol should face left (toward Maple)').toBe('left');
    expect(result.targetCharIdCleared, 'targetCharId should be cleared after arrival').toBe(true);
  });

  // ── TEST 4: Facing toward object when already adjacent (no walk needed) ────

  test('character faces object immediately when already adjacent at wander time', async ({ page }) => {
    test.setTimeout(30_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window._gameEngine?.characters?.length === 3, { timeout: 15_000 });

    // Directly invoke _doInteraction to verify facing is applied at that call site.
    // Uses cafe_espresso (tx=2, ty=11) — a single-tile object in this branch.
    const result = await page.evaluate(() => {
      const engine = window._gameEngine;
      const chars  = engine.characters;
      const maple  = chars.find(c => c.id === 'maple');

      // Use cafe_espresso (tx=2, ty=11) — exists in feature/frg-244 world layout
      const espresso = engine.objectEngine.get('cafe_espresso');
      if (!espresso) return { error: 'cafe_espresso not found' };

      // Place maple below the espresso so vertical (dy) delta dominates after pre-resolution:
      // objCx = 2 + 0.5 = 2.5, objCy = 11 + 0.5 = 11.5
      // maple at (2, 14): dx = 2.5-2 = 0.5, dy = 11.5-14 = -2.5 → |dy| > |dx| → face up
      maple.tx = 2;
      maple.ty = 14;
      maple.facing = 'right'; // Wrong facing — should be corrected to 'up'

      // Reset espresso to idle so the interaction succeeds
      espresso.state = 'idle';

      // Call the interaction handler directly — this is what happens when a char arrives at object
      engine._doInteraction(maple, espresso, 'use');

      const objCx = espresso.position.tx + (espresso.position.tw || 1) / 2;
      const objCy = espresso.position.ty + (espresso.position.th || 1) / 2;
      const dx = objCx - maple.tx;
      const dy = objCy - maple.ty;
      const expectedFacing = Math.abs(dx) >= Math.abs(dy)
        ? (dx > 0 ? 'right' : 'left')
        : (dy > 0 ? 'down' : 'up');

      return {
        maplePos: { tx: maple.tx, ty: maple.ty },
        objPos:   { tx: espresso.position.tx, ty: espresso.position.ty },
        facing:   maple.facing,
        expected: expectedFacing,
      };
    });

    if (result.error) {
      console.log('[SKIP]', result.error);
      return;
    }

    console.log(
      `Maple at (${result.maplePos.tx},${result.maplePos.ty}) → ` +
      `espresso at (${result.objPos.tx},${result.objPos.ty}): ` +
      `facing=${result.facing}, expected=${result.expected}`
    );

    expect(result.facing, `Maple should face ${result.expected} toward espresso`).toBe(result.expected);
  });

  // ── TEST 5: Talk already-nearby — face each other immediately (AI path) ────

  test('characters face each other immediately when already close (AI talk path)', async ({ page }) => {
    test.setTimeout(30_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window._gameEngine?.characters?.length === 3, { timeout: 15_000 });

    // Simulate the AI branch where dist <= 2 → face each other immediately
    const result = await page.evaluate(() => {
      const engine = window._gameEngine;
      const chars  = engine.characters;
      const nyx   = chars.find(c => c.id === 'nyx');
      const maple  = chars.find(c => c.id === 'maple');

      // Place them 1 tile apart (dist ≤ 2 → should face immediately)
      nyx.tx   = 10; nyx.ty   = 5;
      maple.tx = 10; maple.ty = 6;

      nyx.facing   = 'left';  // Wrong — should be corrected
      maple.facing = 'right'; // Wrong — should be corrected

      // Simulate the already-nearby branch in ai.js:
      //   char._updateFacing(target.tx - char.tx, target.ty - char.ty);
      //   target._updateFacing(char.tx - target.tx, char.ty - target.ty);
      nyx._updateFacing(maple.tx - nyx.tx, maple.ty - nyx.ty);
      maple._updateFacing(nyx.tx - maple.tx, nyx.ty - maple.ty);

      return {
        nyx:   { facing: nyx.facing   },
        maple: { facing: maple.facing },
      };
    });

    // nyx is at y=5, maple at y=6 → nyx should face down (toward maple), maple should face up (toward nyx)
    console.log('Nyx facing:', result.nyx.facing, '| Maple facing:', result.maple.facing);
    expect(result.nyx.facing,   'Nyx should face down toward Maple').toBe('down');
    expect(result.maple.facing, 'Maple should face up toward Nyx').toBe('up');
  });
});

