'use strict';
/**
 * REGRESSION — FRG-243
 * Characters play contextual animations during interactions.
 *
 * Tests run against the local dev server (http://localhost:3000) because this
 * feature lives in the feature/frg-243-contextual-interaction-animations branch,
 * not yet deployed to Vercel.
 *
 * The page does NOT expose window._gameEngine by default, so we intercept
 * index.html via page.route() and inject the exposure before the script executes.
 *
 * Test layout:
 *   1. _getInteractAnim mapping — book/desk/bookshelf→reading, bed/kotatsu/sofa/tv→sit, others→phone
 *   2. Sprite key during interaction — startInteraction sets spriteKey + interactAnim correctly
 *   3. Animation clears after timer — interactAnim null + spriteKey reverts to idle after 2000ms
 *   4. Live sim regression — natural interaction uses a contextual spriteKey (_reading|_sit|_phone)
 *   5. All 9 interaction sprites load without network errors
 */
const { test, expect } = require('@playwright/test');

const LOCAL_URL = 'http://localhost:3000';

// ── helpers ──────────────────────────────────────────────────────────────────

/**
 * Intercept index.html served at / and inject:
 *   window._gameEngine = engine
 *   window.SimulationEngine = SimulationEngine
 * so tests can access the engine and its static methods via page.evaluate().
 */
async function injectEngineExposure(page) {
  await page.route('**/', async (route) => {
    const response = await route.fetch();
    let body = await response.text();
    body = body.replace(
      '// ── Initial state ──',
      '// ── Initial state (QA injection) ──\nwindow._gameEngine = engine;\nwindow.SimulationEngine = SimulationEngine;'
    );
    await route.fulfill({ response, body });
  });
}

/**
 * Click the start overlay (if visible) and optionally boost time scale.
 */
async function startEngine(page, timeScale = 20) {
  const overlay = page.locator('#start-overlay');
  if (await overlay.isVisible()) {
    await overlay.click();
  }
  await page.evaluate((scale) => {
    if (window._gameEngine) window._gameEngine.timeScale = scale;
  }, timeScale);
}

/**
 * Poll character states until predicate returns truthy or timeout.
 * Returns the last character state array that satisfied the predicate.
 */
async function pollCharState(page, predicate, timeoutMs = 45_000, intervalMs = 300) {
  const deadline = Date.now() + timeoutMs;
  while (Date.now() < deadline) {
    const chars = await page.evaluate(() =>
      window._gameEngine.characters.map(c => ({
        id: c.id,
        action: c.action,
        interactAnim: c.interactAnim,
        spriteKey: c.spriteKey,
        targetObjectId: c.targetObjectId,
      }))
    );
    if (predicate(chars)) return chars;
    await page.waitForTimeout(intervalMs);
  }
  throw new Error(`pollCharState timed out after ${timeoutMs}ms`);
}

// ── Tests ─────────────────────────────────────────────────────────────────────

test.describe('FRG-243: Contextual Interaction Animations', () => {

  // ── TEST 1: _getInteractAnim mapping ──────────────────────────────────────

  test('_getInteractAnim maps object IDs to the correct animation', async ({ page }) => {
    test.setTimeout(30_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window.SimulationEngine != null, { timeout: 15_000 });

    const results = await page.evaluate(() => {
      const fn = window.SimulationEngine._getInteractAnim.bind(window.SimulationEngine);
      return [
        // book / desk / bookshelf → 'reading'
        { id: 'bookshelf_1',       expected: 'reading', actual: fn('bookshelf_1') },
        { id: 'book_closed',       expected: 'reading', actual: fn('book_closed') },
        { id: 'book_open',         expected: 'reading', actual: fn('book_open') },
        { id: 'desk',              expected: 'reading', actual: fn('desk') },
        { id: 'study_desk_north',  expected: 'reading', actual: fn('study_desk_north') },

        // bed / kotatsu / sofa / tv → 'sit'
        { id: 'bed',               expected: 'sit',     actual: fn('bed') },
        { id: 'kotatsu',           expected: 'sit',     actual: fn('kotatsu') },
        { id: 'living_sofa_left',  expected: 'sit',     actual: fn('living_sofa_left') },
        { id: 'tv',                expected: 'sit',     actual: fn('tv') },
        { id: 'bedroom_bed_main',  expected: 'sit',     actual: fn('bedroom_bed_main') },

        // all other objects → 'phone'
        { id: 'cafe_espresso',     expected: 'phone',   actual: fn('cafe_espresso') },
        { id: 'fridge',            expected: 'phone',   actual: fn('fridge') },
        { id: 'sink',              expected: 'phone',   actual: fn('sink') },
        { id: 'cash_register',     expected: 'phone',   actual: fn('cash_register') },
        { id: 'easel_blank',       expected: 'phone',   actual: fn('easel_blank') },
      ];
    });

    for (const r of results) {
      console.log(`_getInteractAnim('${r.id}'): expected=${r.expected}, actual=${r.actual}`);
      expect(r.actual, `_getInteractAnim('${r.id}') should return '${r.expected}'`).toBe(r.expected);
    }
  });

