    });

    // During interaction
    console.log('During interaction:', JSON.stringify(result.during));
    expect(result.during.action).toBe('interacting');
    expect(result.during.interactAnim).toBe('reading');
    expect(result.during.spriteKey).toBe('maple_reading');

    // After timer expires
    console.log('After timer expiry:', JSON.stringify(result.after));
    expect(result.after.action, 'action should revert to idle').toBe('idle');
    expect(result.after.interactAnim, 'interactAnim should be null after interaction ends').toBeNull();
    expect(result.after.spriteKey, 'spriteKey should revert to maple_idle').toBe('maple_idle');
  });

  // ── TEST 4: Live sim — natural interaction uses contextual spriteKey ───────

  test('interacting character uses a contextual spriteKey in the live sim', async ({ page }) => {
    test.setTimeout(90_000);

    await injectEngineExposure(page);
